module priority_encoder_8x3 (
    input       [7:0] in      ,   // 8 input lines
    output reg  [2:0] out         // 3 output lines
);

always @(*) begin
    if (in[7])
        out = 3'b111;
    else if (in[6])
        out = 3'b110;
    else if (in[5])
        out = 3'b101;
    else if (in[4])
        out = 3'b100;
    else if (in[3])
        out = 3'b011;
    else if (in[2])
        out = 3'b010;
    else if (in[1])
        out = 3'b001;
    else if (in[0])
        out = 3'b000;
    else
        out = 3'b000; // Default case when no inputs are active
end

endmodule

output.rtl/cascaded_encoder.v:
module cascaded_encoder #(parameter N=8, M=$clog2(N)) (
    input wire logic [N-1:0] input_signal,
    output wire logic [M-1:0] out,
    output wire logic [M-2:0] out_upper_half,
    output wire logic [M-2:0] out_lower_half
);

localparam PW = $clog2(M); // Priority Width
wire logic [PW-1:0] prio_signal;

// Extract priority bits
always_comb begin
    integer i;
    prio_signal = 0;
    for (i = 0; i < N; ++i) begin
        prio_signal[i] = input_signal[i];
    end
end

priority_encoder #(.N(N),.M(M)) pe_upper_half (
   .input_signal(input_signal[N-1:N/2]),
   .out(out_upper_half),
   .out_of_range('0),
   .out_of_bound('0),
   .out_of_bound_first('0)
);

priority_encoder #(.N(N),.M(M)) pe_lower_half (
   .input_signal(input_signal[N/2-1:0]),
   .out(out_lower_half),
   .out_of_range('0),
   .out_of_bound('0),
   .out_of_bound_first('0)
);

priority_encoder #(.N((M+1)*(N/2)),.M(M)) pe_merged (
   .input_signal({ out_upper_half, out_lower_half }),
   .out(out)
);

endmodule

output.rtl/Attenuator.sv:
module Attenuator (
    input        clk,
    input        reset,
    input  [4:0] data,
    output reg   ATTN_CLK,
    output reg   ATTN_DATA,
    output reg   ATTN_LE
);

// Internal Signals
reg        clk_div2;
reg  [1:0] current_state, next_state;
reg  [4:0] shift_reg;
reg  [2:0] bit_count;
reg  [4:0] old_data;

// Parameters for FSM States
localparam IDLE  = 2'b00,
           LOAD  = 2'b01,
           SHIFT = 2'b10,
           LATCH = 2'b11;

// Reset Condition
always @(posedge clk or posedge reset) begin
    if (reset) begin
        clk_div2 <= 1'b0;
        current_state <= IDLE;
        ATTN_CLK      <= 1'b0;
        ATTN_DATA     <= 1'b0;
        ATTN_LE       <= 1'b0;
        shift_reg     <= 5'b00000;
        bit_count     <= 3'd0;
        old_data      <= 5'b00000;
    end else begin
        case (current_state)
            IDLE: begin
                if (data!= old_data) begin
                    next_state = LOAD;
                end else begin
                    next_state = current_state;
                end
            end
            LOAD: begin
                shift_reg <= data;
                next_state = SHIFT;
            end
            SHIFT: begin
                ATTN_DATA <= shift_reg[0];
                shift_reg <= shift_reg >> 1;
                bit_count <= bit_count + 1;
                if (bit_count == 5'd3) begin
                    next_state = LATCH;
                end else begin
                    next_state = SHIFT;
                end
            end
            LATCH: begin
                ATTN_LE <= 1'b1;
                next_state = IDLE;
            end
            default: begin
                next_state = IDLE;
            end
        endcase
    end
end

output.rtl/GP.v:
module GP(
  output logic o_generate,
  output logic o_propagate,
  output logic o_Cout,
  input logic i_A,
  input logic i_B,
  input logic i_Cin
);

  assign o_generate = i_A & i_B;
  assign o_propagate = i_A | i_B;
  assign o_Cout = i_Cin ^ (i_A & i_B);

endmodule

