output.rtl/lru_counter_policy.sv:
module lru_counter_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    reg [(NWAYS * $clog2(NWAYS))-1:0] recency [NINDEXES-1:0];

    wire lru_slot_found;
    wire [$clog2(NWAYS)-1:0] lru_slot;

    integer i, j, k;

    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (j = 0; j < NWAYS; j = j + 1) begin
                    recency[i][(j * $clog2(NWAYS)) +: $clog2(NWAYS)] <= $clog2(NWAYS)'(j);
                end
            end
        end else begin
            if (access &&!hit) begin
                recency[index][(way_select * $clog2(NWAYS)) +: $clog2(NWAYS)] <= $clog2(NWAYS)'(NWAYS-1);

                for (k = 0; k < NWAYS; k = k + 1) begin
                    if (k!= way_select) begin
                        recency[index][(k * $clog2(NWAYS)) +: $clog2(NWAYS)] <= recency[index][(k * $clog2(NWAYS)) +: $clog2(NWAYS)] - 1;
                    end
                end
            end

            // Implementation of the LRU replacement logic goes here

            // Example:
            // if (hit) begin
            //     lru_slot_found <= 1'b1;
            //     lru_slot <= recency[index].rfind($clog2(NWAYS));
            // end else begin
            //     lru_slot_found <= 1'b0;
            //     lru_slot <= '0;
            // end

            // Example of how to implement the LRU replacement logic:
            if (hit) begin
                lru_slot_found <= 1'b1;
                lru_slot <= recency[index].rfind($clog2(NWAYS));
            end else begin
                lru_slot_found <= 1'b0;
                lru_slot <= '0;
            end

            if (access && hit) begin
                recency[index][(lru_slot * $clog2(NWAYS)) +: $clog2(NWAYS)] <= $clog2(NWAYS)'(NWAY-1);

                for (k = 0; k < NWAYS; k = k + 1) begin
                    if (k!= lru_slot) begin
                        recency[index][(k * $clog2(NWAYS)) +: $clog2(NWAYS)] <= recency[index][(k * $clog2(NWAYS)) +: $clog2(NWAYS)] - 1;
                    end
                end
            end

        end
    end

endmodule

output.rtl/mru_counter_policy.sv:
module mru_counter_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    reg [(NWAYS * $clog2(NWAYS))-1:0] recency [NINDEXES-1:0];

    // Recency Array Update Logic
    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            for (int i = 0; i < NINDEXES; i = i + 1) begin
                for (int n = 0; n < NWAYS; n = n + 1) begin
                    recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] <= $clog2(NWAYS)'(n);
                end
            end
        end else begin
            if (access &&!hit) begin
                recency[index][((way_select) * $clog2(NWAYS)) +: $clog2(NWAYS)] <= ((way_select) * $clog2(NWAYS)) +: $clog2(NWAYS);
                for (int n = 0; n < NWAYS; n = n + 1) begin
                    if (n!= way_select) begin
                        recency[index][((n) * $clog2(NWAYS)) +: $clog2(NWAYS)] <= recency[index][((n) * $clog2(NWAYS)) +: $clog2(NWAYS)] - 1;
                    end
                end
            end
        end
    end

    // MRU Replacement Logic
    assign way_replace = maxval({recency[index], {($clog2(NWAYS)-1){1'b0}}}]);
    function automatic int maxval;
        int max;
        for (max = 0; max < $clog2(NWAYS); max = max + 1) begin
            if (recency[index][max] == $clog2(NWAYS)'(NWAYS-1)) begin
                break;
            end
        end
        maxval = max;
    endfunction

endmodule

output.rtl/lfu_counter_policy.sv:
module lfu_counter_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32,
    parameter COUNTERW = 2
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    localparam int unsigned MAX_FREQUENCY = $pow(2, COUNTERW) - 1;

    // Frequency array to track next way to be replaced
    reg [(NWAYS * COUNTERW)-1:0] frequency [NINDEXES-1:0];

    integer i, n;

    // Sequential logic for reset and frequency updates
    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    frequency[i][(n * COUNTERW) +: COUNTERW] <= COUNTERW'(0);
                end
            end
        end else begin
            if (access) begin
                // Update frequency counters on cache access
                if (hit) begin
                    // Increment counter for the accessed way
                    if (frequency[index][way_select * COUNTERW +: COUNTERW]!= MAX_FREQUENCY) begin
                        frequency[index][way_select * COUNTERW +: COUNTERW] <= frequency[index][way_select * COUNTERW +: COUNTERW] + 1;
                    }
                end else begin
                    // Decrement counters of other ways if accessed way has reached max frequency
                    if (frequency[index][way_select * COUNTERW +: COUNTERW] == MAX_FREQUENCY) begin
                        for (n = 0; n < NWAYS; n = n + 1) begin
                            if (n!= way_select) begin
                                frequency[index][n * COUNTERW +: COUNTERW] <= 0;
                            end
                        end
                    end

                    // Increment counter for the accessed way
                    frequency[index][way_select * COUNTERW +: COUNTERW] <= 1;
                end
            end

            // Determine the least frequently used way
            integer min_counter = MAX_FREQUENCY;
            integer min_idx = 0;
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    if (frequency[i][n * COUNTERW +: COUNTERW] < min_counter && frequency[i][n * COUNTERW +: COUNTERW]!= 0) begin
                        min_counter = frequency[i][n * COUNTERW +: COUNTERW];
                        min_idx = i;
                    end
                end
            end

            // Assign the least frequently used way to way_replace
            way_replace <= min_idx;
        end
    end

endmodule

