            CA_out[8]  <= q8;
            CA_out[7]  <= q9;
            CA_out[6]  <= q10;
            CA_out[5]  <= q11;
            CA_out[4]  <= q12;
            CA_out[3]  <= q13;
            CA_out[2]  <= q14;
            CA_out[1]  <= q15;
            CA_out[0]  <= q16;
        end
    end

