                bias <= 0;
            end
            5: begin
                w1 <= 0;
                w2 <= 0;
                bias <= 0;
            end
            6: begin
                w1 <= 0;
                w2 <= 0;
                bias <= 0;
            end
            7: begin
                w1 <= 0;
                w2 <= 0;
                bias <= 0;
            end
            8: begin
                w1 <= 0;
                w2 <= 0;
                bias <= 0;
            end
            9: begin
                w1 <= 0;
                w2 <= 0;
                bias <= 0;
            end
        default: begin
            w1 <= 0;
