                    next_state <= idle;
                end
            end

            start: begin
                // Check for valid start bit
                if (ir_signal_in) begin
                    next_state <= decoding;
                    bit_counter <= 0;
                    cycle_counter <= 0;
                    started <= 1;
                end else begin
                    next_state <= idle;
                end
            end

            decoding: begin
                // Decode each bit based on its timing
                if ((bit_counter == 0 || bit_counter == 6 || bit_counter == 12) && ir_signal_in) begin
                    bit_counter <= bit_counter + 1;
                    if (bit_counter == 12) begin
                        // Store the decoded frame
                        ir_frame_reg <= ir_frame_out << 1;
                        ir_frame_out   <= {1'b0, ir_frame_reg};
                        stored <= 1;

                        // Check for end of frame
                        if (ir_frame_reg[11]) begin
                            next_state <= finish;
                        end else begin
                            next_state <= decoding;
                        }
                    end
                end else begin
                    next_state <= idle;
                end
            end

            finish: begin
                // Reset outputs
                ir_frame_valid <= 0;
                ir_frame_out   <= 0;

                // Check for a valid frame
                if (stored) begin
                    // Calculate checksum
                    // Check against expected value
